echo '更新术语: XP'
curl -s   -X PUT 'https://api.yuanshenjian.cn/api/v1/admin/knowledge-terms/8ac1b057-c441-47a5-b652-b40d3aa4c066'   -H "Content-Type: application/json"   -H 'Origin: https://admin.yuanshenjian.cn'   -H "Authorization: Bearer ${ADMIN_API_KEY}"   -d '{"term":"XP","aliases":["Extreme Programming","极限编程"],"definition":"一种强调工程实践、快速反馈和持续改进的软件开发方法。","explanation":"XP（Extreme Programming，极限编程）是一种以工程实践为核心的软件开发方法，目标是在需求变化频繁的情况下仍保持高质量和快速交付。它把很多本来就有效的工程做法推到更高频、更严格的程度，例如持续集成、测试先行、频繁发布和紧密协作。关键要点：1）强调测试驱动开发、重构、持续集成、简单设计等工程实践；2）通过小步提交和快速反馈降低修改成本；3）鼓励开发者之间高频协作，例如结对编程和集体代码所有权；4）把“变化”视为默认前提，而不是需要尽量避免的例外。典型场景是业务变化频繁、团队希望靠扎实工程实践保持交付速度和代码质量的项目，例如边开发边不断调整产品细节的业务系统。","related_article_slugs":[],"references":[{"label":"维基百科","url":"https://en.wikipedia.org/wiki/Extreme_programming"},{"label":"Martin Fowler: XP","url":"https://martinfowler.com/bliki/ExtremeProgramming.html"}],"domains":["author"],"scenes":["author"],"status":"enabled","notes":"补充更完整解释与参考链接。","updated_by":"opencode"}'
