echo '更新术语: TDD'
curl -s   -X PUT 'https://api.yuanshenjian.cn/api/v1/admin/knowledge-terms/92aa7231-b0ac-4de9-ab8f-293923f6cfb2'   -H "Content-Type: application/json"   -H 'Origin: https://admin.yuanshenjian.cn'   -H "Authorization: Bearer ${ADMIN_API_KEY}"   -d '{"term":"TDD","aliases":["测试驱动开发","Test Driven Development"],"definition":"先写失败测试、再写最少实现、最后重构的开发方式。","explanation":"TDD（测试驱动开发）是一种用测试来驱动设计和实现的开发方式，通常以“红-绿-重构”循环来执行：先写一个会失败的测试，再写最少代码让测试通过，最后在测试保护下整理代码结构。它的重点不只是“多写测试”，而是通过测试先行迫使开发者先思考接口、行为和边界条件。关键要点：1）每次只推进一个很小的行为；2）先写失败测试，再写实现；3）在测试持续通过的前提下重构代码；4）测试既验证功能，也帮助设计出更清晰、可测试的代码结构。典型场景是实现一段新业务逻辑时，先写一个失败测试定义预期结果，再逐步补实现，最后重构掉重复或混乱的代码。","related_article_slugs":["tdd-introduction"],"references":[{"label":"维基百科","url":"https://en.wikipedia.org/wiki/Test-driven_development"},{"label":"Martin Fowler: Test Driven Development","url":"https://martinfowler.com/bliki/TestDrivenDevelopment.html"}],"domains":["article","author"],"scenes":["article","author"],"status":"enabled","notes":"补充更完整解释与参考链接。","updated_by":"opencode"}'
echo

echo '更新术语: 重构'
curl -s   -X PUT 'https://api.yuanshenjian.cn/api/v1/admin/knowledge-terms/2b73064a-57ba-465b-8788-1de12e5e95a2'   -H "Content-Type: application/json"   -H 'Origin: https://admin.yuanshenjian.cn'   -H "Authorization: Bearer ${ADMIN_API_KEY}"   -d '{"term":"重构","aliases":["Refactoring","代码重构"],"definition":"在不改变外部可观察行为的前提下，持续改善代码内部结构的过程。","explanation":"重构是通过一系列小而安全的代码调整来改善内部结构，同时保持系统对外行为不变。它的目标通常不是增加新功能，而是降低复杂度、提升可读性、减少重复和改善可维护性。重构通常需要测试作为保护网，否则很容易把“改善结构”变成“顺手改坏逻辑”。关键要点：1）外部行为保持不变；2）以小步、可验证的方式持续进行；3）常用来处理重复代码、过长函数、职责混乱等问题；4）通常依赖自动化测试来降低风险。典型例子是把一个几百行的大函数拆成多个命名清晰的小函数，或者把散落在多处的重复逻辑提取成统一方法。","related_article_slugs":["agile-growth-assistant","beyond-training","avoid-ineffective-knowledge-management","three-practices-of-simple-design"],"references":[{"label":"维基百科","url":"https://en.wikipedia.org/wiki/Code_refactoring"},{"label":"Martin Fowler: Refactoring","url":"https://martinfowler.com/books/refactoring.html"}],"domains":["article","author"],"scenes":["article","author"],"status":"enabled","notes":"补充更完整解释与参考链接。","updated_by":"opencode"}'
echo

